  const [value, setValue] = React.useState(countryCodes[0]);

  return (
    <div style={{ width: '22rem' }}>
      <CountrySelect
        countryCodes={countryCodes}
        value={value}
        onChange={(_e, newValue) => setValue(newValue)}
      />
    </div>
  );
}

function ErrorCountrySelectDemo() {
  const countryCodes = [
    { countryName: 'China', countryCode: 'CN', callingCode: '86', countryFlag: '🇨🇳' },
    { countryName: 'United States', countryCode: 'US', callingCode: '1', countryFlag: '🇺🇸' },
