  const [value, setValue] = React.useState(null);

  return (
    <div style={{ width: '22rem' }}>
      <CountrySelect
        countryCodes={countryCodes}
        value={value}
        onChange={(_e, newValue) => setValue(newValue)}
        error={!value}
        helperText={!value ? '请选择国家/地区' : ''}
      />
