        required
        value={password}
        onChange={(e) => setPassword(e.target.value)}
      />
    </FormControl>
  );
}
```

## 错误态 + helperText

```jsx live
function ErrorPasswordInputDemo() {
  const [password, setPassword] = React.useState('');
  const hasError = password.length > 0 && password.length < 6;

  return (
    <FormControl variant="outlined" size="small" error={hasError} fullWidth style={{ width: '22rem' }}>
      <PasswordInput
        label="密码"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        error={hasError}
        helperText={hasError ? '密码长度至少为6位' : ''}
      />
