}
```

## 表单集成示例

```jsx live
function FormPasswordInputDemo() {
  const [formData, setFormData] = React.useState({
    username: '',
    password: '',
  });
  const [errors, setErrors] = React.useState({});

  const handleSubmit = (e) => {
    e.preventDefault();
    const newErrors = {};

    if (!formData.username) {
      newErrors.username = '请输入用户名';
    }
    if (!formData.password) {
      newErrors.password = '请输入密码';
    } else if (formData.password.length < 6) {
      newErrors.password = '密码长度至少为6位';
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    alert('登录成功！');
    setErrors({});
  };

  return (
    <form onSubmit={handleSubmit} style={{ width: '22rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
      <FormControl variant="outlined" size="small" error={!!errors.username} fullWidth>
        <InputLabel>用户名</InputLabel>
        <OutlinedInput
          label="用户名"
          value={formData.username}
          onChange={(e) => setFormData({ ...formData, username: e.target.value })}
        />
        {errors.username && (
          <FormHelperText error>{errors.username}</FormHelperText>
        )}
      </FormControl>

      <FormControl variant="outlined" size="small" error={!!errors.password} fullWidth>
        <PasswordInput
          label="密码"
          value={formData.password}
          onChange={(e) => setFormData({ ...formData, password: e.target.value })}
          error={!!errors.password}
          helperText={errors.password}
        />
      </FormControl>

      <Button type="submit" variant="contained" fullWidth>
        登录
      </Button>
    </form>
  );
}
```

## API

### PasswordInput Props

| 属性       | 类型        | 默认值  | 描述                                        |
| ---------- | ----------- | ------- | ------------------------------------------- |
| label      | `string`    | -       | 输入框标签                                  |
| error      | `boolean`   | `false` | 是否显示错误态                              |
| helperText | `ReactNode` | -       | 错误提示内容（仅在 `error=true` 时显示）    |
| autoFocus  | `boolean`   | `false` | 是否自动聚焦                                |
| required   | `boolean`   | `false` | 是否必填                                    |
| ref        | `Ref`       | -       | 转发的 ref 引用                             |
| ...props   | -           | -       | 其他 MUI `OutlinedInput` 支持的所有原生属性 |

### 使用说明

:::tip 重要
`PasswordInput` 组件需要使用 MUI 的 `FormControl` 包裹才能实现 label 浮动动画效果。建议用法：

```jsx
<FormControl variant="outlined" size="small" error={error} fullWidth>
  <PasswordInput
    label="密码"
    value={password}
    onChange={(e) => setPassword(e.target.value)}
    error={error}
    helperText={helperText}
  />
</FormControl>
```

:::

### 特性说明

- **密码可见性切换**：点击右侧眼睛图标可切换密码的显示/隐藏状态
- **自动完成**：内置 `autoComplete="new-pwd"` 属性
- **错误提示**：使用 `ErrorHelperText` 组件统一错误样式
- **尺寸**：固定为 `small` 尺寸
- **Ref 转发**：支持通过 `ref` 访问底层 `OutlinedInput` 实例
- **Label 浮动**：配合 `FormControl` 使用时，label 会在输入框获得焦点或有值时自动浮动到上方

## 相关组件

- [ErrorHelperText](./error-helper-text)
- [CountrySelect](./country-select)

