function BasicProTableDemo() {
  const allData = React.useMemo(
    () =>
      Array.from({ length: 36 }, (_, index) => ({
        id: String(index + 1),
        name: `User ${index + 1}`,
        email: `user${index + 1}@example.com`,
        status: ['active', 'inactive', 'pending'][index % 3],
      })),
    [],
  );

  const columns = [
    { title: 'ID', key: 'id', width: '4rem' },
    { title: 'Name', key: 'name' },
    { title: 'Email', key: 'email' },
    { title: 'Status', key: 'status' },
  ];

  const filters = [
    {
      key: 'keyword',
      type: FilterType.TEXT_INPUT,
      config: { placeholder: 'Search by name or email' },
    },
    {
      key: 'status',
      type: FilterType.CHECKBOX,
      config: {
        label: 'Status',
        options: [
          { value: 'active', label: 'Active' },
          { value: 'inactive', label: 'Inactive' },
          { value: 'pending', label: 'Pending' },
        ],
      },
    },
  ];

  return (
    <ProTable
      columns={columns}
      filters={filters}
      defaultPagin={{ pageSize: 8 }}
      slotProps={{
        filters: {
          defaultValues: { keyword: '', status: [] },
        },
        table: {
          tableTitle: ({ pagin }) => (
            <div style={{ marginBottom: '0.75rem', color: '#666', fontSize: '0.875rem' }}>
              Total: {pagin.totalCount}
            </div>
          ),
        },
      }}
      onSearch={async ({ filters, pageNo = 1, pageSize = 8 }) => {
        let rows = allData;

        if (filters.keyword) {
          const keyword = filters.keyword.toLowerCase();
          rows = rows.filter(
            (item) => item.name.toLowerCase().includes(keyword) || item.email.toLowerCase().includes(keyword),
          );
        }

        if (filters.status?.length) {
          rows = rows.filter((item) => filters.status.includes(item.status));
        }

        const start = (pageNo - 1) * pageSize;
        return {
          data: rows.slice(start, start + pageSize),
          totalCount: rows.length,
        };
      }}
    />
  );
}

function ProTableRefDemo() {
  const tableRef = React.useRef(null);
  const [result, setResult] = React.useState(null);
  const rows = [
    { id: '1', name: 'Alice', email: 'alice@example.com', status: 'active' },
    { id: '2', name: 'Bob', email: 'bob@example.com', status: 'inactive' },
  ];

  return (
    <div>
      <ProTable
        ref={tableRef}
        columns={[
          { title: 'Name', key: 'name' },
          { title: 'Email', key: 'email' },
          { title: 'Status', key: 'status' },
        ]}
        onSearch={async () => ({ data: rows, totalCount: rows.length })}
      />
      <div style={{ display: 'flex', gap: '0.5rem', marginTop: '0.75rem' }}>
        <Button variant="outlined" size="small" onClick={() => setResult(tableRef.current?.getSearchParams())}>
          getSearchParams()
        </Button>
        <Button variant="outlined" size="small" onClick={() => tableRef.current?.refresh()}>
          refresh()
        </Button>
        <Button variant="outlined" size="small" onClick={() => tableRef.current?.clearSearchParams()}>
          clearSearchParams()
        </Button>
      </div>
      <pre style={{ marginTop: '0.75rem', background: '#fafafa', padding: '0.75rem', fontSize: '0.8rem' }}>
        {JSON.stringify(result, null, 2)}
      </pre>
    </div>
  );
}

